376→void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
377→{
378→	if (!Node) return;
379→
380→	UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
381→
