419→void ALFPWorldMapPlayerController::EnterBattle(ALFPWorldMapNode* BattleNode)
420→{
421→	if (!BattleNode) return;
422→
423→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
424→	if (!GI) return;
425→
426→	ALFPWorldMapManager* Manager = GetWorldMapManager();
427→	if (!Manager) return;
428→
429→	// 保存世界地图快照
430→	FLFPWorldMapSnapshot Snapshot;
431→	Snapshot.WorldMapName = Manager->GetCurrentWorldMapName();
432→	if (ULFPWorldMapPlayerState* PS = Manager->GetPlayerState())
433→	{
434→		Snapshot.CurrentNodeID = PS->CurrentNodeID;
435→		Snapshot.CurrentTurn = PS->CurrentTurn;
436→		Snapshot.VisitedNodeIDs = PS->VisitedNodeIDs;
437→		Snapshot.RevealedNodeIDs = PS->RevealedNodeIDs;
438→	}
439→
440→	// 收集已触发节点
441→	for (const auto& Pair : Manager->GetNodeMap())
442→	{
443→		if (Pair.Value && Pair.Value->bHasBeenTriggered)
444→		{
445→			Snapshot.TriggeredNodeIDs.Add(Pair.Key);
446→		}
447→	}
448→
449→	GI->SaveWorldMapSnapshot(Snapshot);
450→
451→	// 设置战斗请求
452→	FLFPBattleRequest Request;
453→	Request.SourceNodeID = BattleNode->NodeID;
454→	Request.BattleMapName = BattleNode->BattleMapName;
455→	Request.StarRating = BattleNode->StarRating;
456→	Request.bCanEscape = BattleNode->bCanEscape;
457→	GI->SetBattleRequest(Request);
458→
459→	// 切换到战斗关卡
460→	GI->TransitionToBattle(TEXT(""));
461→}
