	UFUNCTION(BlueprintCallable, Category = "World Map|Fog")
	void UpdateFog();

	// 获取从指定节点出发、图距离不超过 MaxDistance 的所有节点
	UFUNCTION(BlueprintCallable, Category = "World Map|Fog")
	TSet<int32> GetNodesWithinGraphDistance(int32 StartNodeID, int32 MaxDistance) const;

