261→	// 先销毁边
262→	for (auto& Pair : EdgeMap)
263→	{
264→		if (Pair.Value)
265→		{
266→			Pair.Value->Destroy();
267→		}
268→	}
269→	EdgeMap.Empty();
270→
271→	// 再销毁节点
272→	for (auto& Pair : NodeMap)
273→	{
274→		if (Pair.Value)
275→		{
276→			Pair.Value->Destroy();
277→		}
278→	}
279→	NodeMap.Empty();
280→
281→	AdjacencyList.Empty();
282→	NodeEdgeIndex.Empty();
283→	NextNodeID = 0;
284→}
