360→		CSVContent += FString::Printf(TEXT("%s,%d,%f,%f,%s,%s,%d,%s,%s,%s\n"),
361→			*RowName,
362→			Row.NodeID,
363→			Row.PosX,
364→			Row.PosY,
365→			*NodeTypeStr,
366→			*Row.BattleMapName,
367→			Row.StarRating,
368→			Row.bCanEscape ? TEXT("True") : TEXT("False"),
369→			*Row.EventID,
370→			*Row.PrerequisiteNodeIDs);
