372→
373→	// 确保目录存在
374→	FString Directory = FPaths::GetPath(FilePath);
375→	if (!FPaths::DirectoryExists(Directory))
376→	{
377→		IFileManager::Get().MakeDirectory(*Directory, true);
378→	}
379→
380→	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *FilePath,
381→		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
382→
383→	if (bSuccess)
384→	{
385→		UE_LOG(LogTemp, Log, TEXT("SaveNodesToCSV: 保存 %d 个节点到 %s"), NodeMap.Num(), *FilePath);
386→	}
387→	else
388→	{
389→		UE_LOG(LogTemp, Error, TEXT("SaveNodesToCSV: 保存失败 %s"), *FilePath);
390→	}
